Deno.serve(async (req: Request) => {
  if (req.method === "OPTIONS") return new Response(null, { headers: corsHeaders });

  try {
    const sb = createClient(
      Deno.env.get("SUPABASE_URL")!,
      Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!
    );

    const total_days = 112;

    await sb.from("programs").update({ total_days, name: "M2F Perform 3.2", updated_at: new Date().toISOString() }).eq("id", PROGRAM_ID);
    await sb.from("program_days").delete().eq("program_id", PROGRAM_ID);

    const rows: any[] = [];
    for (let w = 0; w < 16; w++) {
      const week = SPEC_DATA[w];
      for (let d = 0; d < week.length; d++) {
        const dayNum = w * 7 + d + 1;
        const dayData = week[d];
        rows.push({
          program_id: PROGRAM_ID,
          day_number: dayNum,
          label: dayData.day_label,
          exercises: dayData.exercises,
        });
      }
    }

    const results: string[] = [];
    for (let i = 0; i < rows.length; i += 10) {
      const chunk = rows.slice(i, i + 10);
      const { error } = await sb.from("program_days").insert(chunk);
      if (error) {
        results.push(`\u274c Chunk ${i}-${i + chunk.length}: ${error.message}`);
      } else {
        results.push(`\u2705 Days ${chunk[0].day_number}-${chunk[chunk.length - 1].day_number} inserted`);
      }
    }

    return new Response(JSON.stringify({
      success: true,
      total_days,
      total_rows: rows.length,
      results,
    }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });
  } catch (err) {
    return new Response(JSON.stringify({ error: err.message }), {
      status: 500,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});
